import { describe, it, expect } from 'vitest';
import { slugify } from '../slugify';

describe('slugify', () => {
  it('should lowercase the input', () => {
    expect(slugify('HELLO')).toBe('hello');
  });

  it('should replace non-alphanumeric characters with hyphens', () => {
    expect(slugify('hello world!')).toBe('hello-world');
  });

  it('should collapse consecutive hyphens into one', () => {
    expect(slugify('hello---world')).toBe('hello-world');
  });

  it('should trim leading and trailing hyphens', () => {
    expect(slugify('--hello world--')).toBe('hello-world');
  });

  it('should handle an empty string', () => {
    expect(slugify('')).toBe('');
  });

  it('should handle a string with only non-alphanumeric characters', () => {
    expect(slugify('!!@#$%^&*()')).toBe('');
  });

  it('should preserve alphanumeric characters and hyphens from original', () => {
    expect(slugify('a-B_c')).toBe('a-b_c');
  });
});

import { clamp } from '../src/util/clamp';

describe('clamp', () => {
  it('should return the lower bound when n is below the range', () => {
    expect(clamp(-5, 0, 10)).toBe(0);
  });

  it('should return the upper bound when n is above the range', () => {
    expect(clamp(15, 0, 10)).toBe(10);
  });

  it('should return the original number when n is within the range', () => {
    expect(clamp(5, 0, 10)).toBe(5);
  });

  it('should handle floating point numbers correctly', () => {
    expect(clamp(3.14, 0, 5)).toBe(3.14);
  });

  it('should work when lo equals hi', () => {
    expect(clamp(100, 5, 5)).toBe(5);
  });
});

