import { describe, it, expect } from 'vitest';
import { uniqueBy } from '../src/util/uniq';

describe('uniqueBy', () => {
  it('should return array with unique elements based on key function, preserving first occurrence', () => {
    const input = [{ id: 1, name: 'a' }, { id: 2, name: 'b' }, { id: 1, name: 'c' }];
    const result = uniqueBy(input, (item) => item.id);
    expect(result).toEqual([{ id: 1, name: 'a' }, { id: 2, name: 'b' }]);
  });

  it('should handle empty array', () => {
    expect(uniqueBy([], (x: unknown) => x)).toEqual([]);
  });

  it('should work with primitive keys and preserve order', () => {
    const arr = [3, 1, 2, 3, 4, 1, 5];
    const result = uniqueBy(arr, (x) => x);
    expect(result).toEqual([3, 1, 2, 4, 5]);
  });

  it('should handle objects with different key types', () => {
    const items = [
      { val: 'x', group: 1 },
      { val: 'y', group: 2 },
      { val: 'z', group: 1 },
    ];
    const result = uniqueBy(items, (item) => item.group);
    expect(result).toEqual([
      { val: 'x', group: 1 },
      { val: 'y', group: 2 },
    ]);
  });
});

