import { describe, it, expect } from 'vitest';
import { RingBuffer } from '../src/util/ring';

describe('RingBuffer', () => {
  it('should drop oldest element when full and maintain capacity', () => {
    const buffer = new RingBuffer<number>(3);
    buffer.push(1);
    buffer.push(2);
    buffer.push(3);
    buffer.push(4); // should drop 1
    expect(buffer.size).toBe(3);
    expect(buffer.toArray()).toEqual([2, 3, 4]);
  });
});

import { describe, it, expect } from 'vitest';
import { mergeRanges } from '../src/util/ranges';

describe('mergeRanges', () => {
  it('should merge overlapping ranges', () => {
    const input: Array<[number, number]> = [[1, 3], [2, 6], [8, 10], [15, 18]];
    const expected: Array<[number, number]> = [[1, 6], [8, 10], [15, 18]];
    expect(mergeRanges(input)).toEqual(expected);
  });

  it('should merge adjacent ranges', () => {
    const input: Array<[number, number]> = [[1, 2], [2, 3], [3, 4]];
    const expected: Array<[number, number]> = [[1, 4]];
    expect(mergeRanges(input)).toEqual(expected);
  });

  it('should return empty array for empty input', () => {
    expect(mergeRanges([])).toEqual([]);
  });

  it('should handle single range', () => {
    expect(mergeRanges([[5, 10]])).toEqual([[5, 10]]);
  });
});

import { describe, it, expect, vi } from 'vitest';
import { debounceAsync } from '../src/util/debounce';

describe('debounceAsync', () => {
  it('should resolve the latest call and reject previous calls', async () => {
    const fn = vi.fn().mockImplementation(async (x: number) => x * 2);
    const debounced = debounceAsync(fn, 50);

    const promise1 = debounced(1);
    const promise2 = debounced(2);
    const promise3 = debounced(3);

    await expect(promise1).rejects.toThrow();
    await expect(promise2).rejects.toThrow();
    await expect(promise3).resolves.toBe(6);
  });

  it('should only call the underlying function once per burst', async () => {
    const fn = vi.fn().mockResolvedValue('resolved');
    const debounced = debounceAsync(fn, 50);

    debounced('a');
    debounced('b');
    await debounced('c');

    expect(fn).toHaveBeenCalledTimes(1);
  });
});

import { describe, it, expect } from 'vitest';
import { extractTestId } from './src/repair/test-id';

describe('extractTestId', () => {
  it('returns native id when no annotation comment exists', () => {
    const file = 'a.test.ts';
    const fullName = 'should do something';
    const source = `
      it('should do something', () => {});
    `;
    const result = extractTestId(file, fullName, source);
    expect(result).toEqual({ id: 'a.test.ts::should do something', source: 'native' });
  });

  it('returns annotation id when matching comment is within 3 lines above', () => {
    const file = 'b.test.ts';
    const fullName = 'works';
    const source = `
      // @reasonix-test-id: my-slug
      it('works', () => {});
    `;
    const result = extractTestId(file, fullName, source);
    expect(result).toEqual({ id: 'my-slug', source: 'annotation' });
  });

  it('respects the 3-line limit: exactly 3 lines above matches', () => {
    const file = 'c.test.ts';
    const fullName = 'three lines';
    const source = `
      // @reasonix-test-id: three-slug
      // line1
      // line2
      it('three lines', () => {});
    `;
    const result = extractTestId(file, fullName, source);
    expect(result).toEqual({ id: 'three-slug', source: 'annotation' });
  });

  it('does not match comment more than 3 lines above (4 lines)', () => {
    const file = 'd.test.ts';
    const fullName = 'too far';
    const source = `
      // @reasonix-test-id: wrong
      // line1
      // line2
      // line3
      it('too far', () => {});
    `;
    const result = extractTestId(file, fullName, source);
    expect(result).toEqual({ id: 'd.test.ts::too far', source: 'native' });
  });

  it('does not match comment for a different test name', () => {
    const file = 'e.test.ts';
    const fullName = 'other test';
    const source = `
      // @reasonix-test-id: not-for-you
      it('different test', () => {});
    `;
    const result = extractTestId(file, fullName, source);
    expect(result).toEqual({ id: 'e.test.ts::other test', source: 'native' });
  });

  it('picks correct comment when multiple exist', () => {
    const file = 'f.test.ts';
    const fullName = 'second test';
    const source = `
      // @reasonix-test-id: first-slug
      it('first test', () => {});
      // @reasonix-test-id: second-slug
      it('second test', () => {});
    `;
    const result = extractTestId(file, fullName, source);
    expect(result).toEqual({ id: 'second-slug', source: 'annotation' });
  });

  it('does not misidentify a non-comment line with @reasonix-test-id', () => {
    const file = 'g.test.ts';
    const fullName = 'no comment';
    const source = `
      const x = '// @reasonix-test-id: ignored';
      it('no comment', () => {});
    `;
    const result = extractTestId(file, fullName, source);
    expect(result).toEqual({ id: 'g.test.ts::no comment', source: 'native' });
  });
});

import { describe, it, expect } from 'vitest';
import { pairRedGreen } from '../../src/events/pair';

describe('pairRedGreen', () => {
  it('should return the most recent fail→pass transition per test_id, ignoring test_ids that never passed', () => {
    const events = [
      { type: 'test', test_id: 't1', status: 'fail', ts: 1 },
      { type: 'test', test_id: 't1', status: 'fail', ts: 2 },
      { type: 'test', test_id: 't1', status: 'pass', ts: 3 },
      { type: 'test', test_id: 't1', status: 'fail', ts: 4 },
      { type: 'test', test_id: 't1', status: 'pass', ts: 5 },
      { type: 'test', test_id: 't2', status: 'fail', ts: 10 },
      { type: 'test', test_id: 't2', status: 'fail', ts: 11 },
      { type: 'test', test_id: 't3', status: 'pass', ts: 20 },
      { type: 'test', test_id: 't3', status: 'fail', ts: 21 },
      { type: 'test', test_id: 't3', status: 'pass', ts: 22 },
